mapper.select:
SELECT conversation_id, session_id, user_id, dept_id, question, answer, source_chunks, top_score,
       confidence_level, no_answer, feedback, feedback_remark, create_time
FROM kb_qa_conversation


        AND (question LIKE CONCAT('%', #{keyword}, '%') OR answer LIKE CONCAT('%', #{keyword}, '%'))


        AND no_answer = #{noAnswer}


        AND feedback = #{feedback}


        AND confidence_level = #{confidenceLevel}


ORDER BY create_time DESC, conversation_id DESC

mapper.update:
UPDATE kb_qa_conversation
SET feedback = #{feedback},
    feedback_remark = #{feedbackRemark}
WHERE conversation_id = #{conversationId}
